let heartRate = Math.floor(Math.random() * 80) + 60;
let spo2 = Math.floor(Math.random() * 15) + 85;
let temperature = Number((Math.random() * 3 + 35).toFixed(1));

msg.payload = {
    userId: "ELD001",
    deviceId: "SIM001",
    heartRate: heartRate,
    spo2: spo2,
    temperature: temperature,
    timestamp: new Date().toISOString(),
    systemVersion: "v1.0"
};

return msg;

let hr = msg.payload.heartRate;
let spo2 = msg.payload.spo2;
let temp = msg.payload.temperature;

let valid = true;
let error = null;

// Heart Rate range check
if (hr < 40 || hr > 180) {
    valid = false;
    error = "Heart Rate out of realistic range";
}

// SpO2 range check
if (spo2 < 70 || spo2 > 100) {
    valid = false;
    error = "SpO2 out of realistic range";
}

// Temperature range check
if (temp < 34 || temp > 42) {
    valid = false;
    error = "Temperature out of realistic range";
}

// Append validation result
msg.payload.valid = valid;
msg.payload.error = error;

return msg;
